  'weifang/woodprint': ('ภาพพิมพ์หยางเจียปู้', 'หมู่บ้านแห่งนี้สืบทอดการทำภาพพิมพ์ไม้สำหรับเทศกาลตรุษจีนมานานกว่า 600 ปี'),
  'weifang/dragon': ('ว่าวมังกร', 'ว่าวมังกรที่มีความยาวกว่าร้อยเมตรถือเป็นไฮไลต์สำคัญของเทศกาลว่าว'),
  'weifang/radish': ('หัวไชเท้าเวยฟาง', 'หัวไชเท้าสีเขียวที่สามารถรับประทานสดได้เหมือนผลไม้ถือเป็นของดีขึ้นชื่อของเมืองนี้'),
  'dezhou/chicken': ('ไก่ตุ๋นเต๋อโจว', 'ไก่ตุ๋นเนื้อนุ่มจนหลุดจากกระดูกเมนูนี้เคยเป็นอาหารที่ถวายแด่จักรพรรดิในสมัยก่อน'),
  'dezhou/sun': ('หุบเขาพลังงานแสงอาทิตย์', 'ที่นี่เป็นที่ตั้งของหนึ่งในวิทยาเขตด้านพลังงานแสงอาทิตย์ที่ใหญ่ที่สุดในโลก'),
  'dezhou/grapes': ('แหล่งปลูกเมลอนและองุ่น', 'ที่ราบอันอุดมสมบูรณ์แห่งนี้เต็มไปด้วยผลเมลอนและองุ่นในช่วงฤดูร้อน'),
  'dezhou/train': ('เมืองท่าคลองขุด', 'ในอดีตที่นี่เคยเป็นเมืองท่าขนส่งธัญพืชที่คึกคักที่สุดแห่งหนึ่งในยุคคลองต้ายวิ่นเหอ'),
  'xuzhou/stone': ('ภาพสลักหินสมัยราชวงศ์ฮั่น', 'แผ่นหินจากสุสานสมัยราชวงศ์ฮั่นช่วยถ่ายทอดภาพวิถีชีวิตของผู้คนเมื่อ 2,000 ปีก่อน'),
  'xuzhou/terracotta': ('กองทัพทหารดินเผา', 'มีการขุดพบกองทัพทหารดินเผาที่มีขนาดเล็กกว่าแต่เก่าแก่กว่าที่นี่'),
  'xuzhou/lake': ('ทะเลสาบอวิ๋นหลง', 'พื้นที่ริมทะเลสาบอวิ๋นหลงเปรียบเสมือนปอดสีเขียวของเมืองนี้'),
  'xuzhou/skewer': ('วัฒนธรรมปิ้งย่าง', 'เมืองหลวงแห่งการปิ้งย่างของจีนที่อบอวลไปด้วยกลิ่นเนื้อแกะย่างบนเตาถ่านตลอดทั้งคืน'),
  'zhenjiang/vinegar': ('จิ๊กโฉ่วเจิ้นเจียง', 'น้ำส้มสายชูดำจากข้าวเหนียวที่มีชื่อเสียงที่สุดของจีนแห่งนี้หมักบ่มมานานกว่า 1,400 ปี'),
  'zhenjiang/temple': ('วัดจินซาน', 'วัดที่เป็นฉากในตำนานนางพญางูขาวแห่งนี้ตั้งตระหง่านอยู่ริมแม่น้ำ'),
  'zhenjiang/pot': ('บะหมี่ฝาหม้อ', 'บะหมี่ฝาหม้อที่ปรุงด้วยการวางฝาไม้ปิดไว้บนหม้อขณะต้มเป็นเมนูอาหารเช้าขึ้นชื่อของท้องถิ่น'),
  'zhenjiang/bridge': ('พื้นที่ริมแม่น้ำแยงซี', 'พื้นที่ริมฝั่งแม่น้ำบริเวณเขาสามลูกรายล้อมไปด้วยสวนสาธารณะสำหรับเดินเล่น'),
  'jiaxing/zongzi': ('บ๊ะจ่าง', 'ที่นี่คือเมืองหลวงแห่งบ๊ะจ่าง ข้าวเหนียวห่อใบไผ่ที่เป็นเอกลักษณ์'),
  'jiaxing/boat': ('เรือแดงแห่งทะเลสาบหนานหู', 'ในปี ค.ศ. 1921 การประชุมสมัชชาพรรคครั้งแรกได้จัดขึ้นบนเรือลำหนึ่งในทะเลสาบแห่งนี้'),
  'jiaxing/silk': ('เมืองแห่งผ้าไหม', 'ผ้าไหมเจียงหนานถูกทอขึ้นในเมืองริมคลองแห่งนี้มานานหลายศตวรรษ'),
  'jiaxing/canal': ('เมืองน้ำอูเจิ้น', 'สัมผัสบรรยากาศเมืองริมน้ำที่เต็มไปด้วยสะพานหินและแสงไฟจากโคมจีนด้วยการล่องเรือ'),
  'lishui/mountains': ('ยอดเขาเขียวขจี', 'พื้นที่ที่เต็มไปด้วยภูเขามากที่สุดในมณฑลเจ้อเจียง ซึ่งมีหมู่บ้านบนนาขั้นบันไดที่สูงเสียดฟ้า'),
  'lishui/camera': ('สวรรค์ของช่างภาพ', 'นาขั้นบันไดท่ามกลางสายหมอกเป็นหนึ่งในทิวทัศน์ที่ถูกถ่ายภาพมากที่สุดในประเทศจีน'),
  'lishui/mushroom': ('ดินแดนแห่งเห็ด', 'อำเภอชิงหยวนถือเป็นแหล่งกำเนิดของการเพาะเห็ดที่สำคัญที่สุดแห่งหนึ่งของโลก'),
  'lishui/raft': ('ล่องแพไม้ไผ่', 'ล่องแพไม้ไผ่ไปตามแม่น้ำโอวเจียงเพื่อชมความงดงามของหุบเขาสีเขียวขจี'),
  'anqing/opera': ('งิ้วหวงเหมย', 'ศิลปะการแสดงงิ้วท้องถิ่นที่เป็นที่รักมากที่สุดของจีนได้ถือกำเนิดขึ้นที่นี่'),
  'anqing/pagoda': ('เจดีย์เจิ้นเฟิง', 'เจดีย์เก่าแก่อายุกว่า 400 ปีริมแม่น้ำแยงซีที่ได้รับการขนานนามว่าเป็นประภาคารแห่งแรกของแม่น้ำ'),
  'anqing/tea': ('ชาเยว่ซี', 'ชาเขียวรสเลิศที่มีกลิ่นหอมเป็นเอกลักษณ์ซึ่งปลูกบนพื้นที่ลาดชันของเทือกเขาต้าเปี๋ย'),
  'anqing/sail': ('ประตูแม่น้ำ', 'เมืองท่าริมแม่น้ำแยงซีในมณฑลอันฮุยที่มีความหมายของชื่อว่าการเฉลิมฉลองอย่างสันติ'),
  'ganzhou/orange': ('ส้มนาเวลก้านหนาน', 'ส้มนาเวลที่ขึ้นชื่อว่าหวานที่สุดในจีนเติบโตได้ดีในผืนดินสีแดงแห่งนี้'),
  'ganzhou/house': ('บ้านดินชาวฮากกา', 'วัฒนธรรมชาวฮากกาที่สืบทอดมายาวนานหลายศตวรรษผ่านบ้านทรงกลมที่สร้างเหมือนป้อมปราการ'),
  'ganzhou/pavilion': ('ศาลาอวี้กู', 'ศาลาที่กวีสมัยราชวงศ์ซ่งเคยแต่งบทกลอนถึง ซึ่งตั้งอยู่บนจุดชมวิวบริเวณทางแยกของแม่น้ำ'),
  'ganzhou/star': ('การเดินทัพทางไกล', 'เมืองแห่งนี้เป็นจุดเริ่มต้นของการเดินทัพทางไกลของกองทัพแดง'),
  'putian/shrine': ('ศาลเจ้าแม่หม่าโจ้ว', 'เจ้าแม่หม่าโจ้วเทพีผู้คุ้มครองชาวเรือประสูติที่นี่ และมีศาลเจ้าหลักตั้งอยู่บนเกาะเหมยโจว'),
  'putian/lychee': ('สวนลิ้นจี่', 'ต้นลิ้นจี่ที่มีอายุเก่าแก่กว่าพันปีทำให้เมืองนี้ได้รับฉายาว่าเป็นดินแดนแห่งลิ้นจี่'),
  'putian/shoe': ('เมืองหลวงแห่งรองเท้า', 'สัดส่วนการผลิตรองเท้ากีฬาจำนวนมหาศาลของโลกมาจากโรงงานในเมืองนี้'),
  'putian/wave': ('เกาะเหมยโจว', 'เกาะที่เดินทางไปถึงได้ด้วยเรือเฟอร์รี่แห่งนี้มีชื่อเสียงในเรื่องชายหาดและเทศกาลงานวัด'),
  'mudanjiang/snow': ('หมู่บ้านหิมะ', 'หมู่บ้านในเทพนิยายที่ถูกปกคลุมด้วยหิมะหนานุ่มและส่องประกายงดงามในฤดูหนาว'),
  'mudanjiang/lake': ('ทะเลสาบจิ้งป๋อ', 'ทะเลสาบที่เกิดจากการระเบิดของภูเขาไฟซึ่งมีน้ำตกเตี้ยวสุ่ยโหลวที่ยังคงไหลแม้ในฤดูหนาว'),
  'mudanjiang/tiger': ('สวนเสือไซบีเรีย', 'หนึ่งในเขตรักษาพันธุ์เสือไซบีเรียที่ใหญ่ที่สุดในโลก'),
  'mudanjiang/ski': ('ฤดูกาลเล่นสกี', 'ฤดูหนาวที่มีหิมะตกยาวนานทำให้ภูมิภาคนี้เป็นจุดหมายปลายทางของนักสกีทุกคน'),
  'changzhou/dino': ('สวนไดโนเสาร์', 'สวนสนุกธีมไดโนเสาร์ที่มีชื่อเสียงที่สุดของจีนและเป็นสัญลักษณ์สำหรับครอบครัวของเมืองนี้'),
  'changzhou/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์ที่สูงที่สุดในโลกด้วยความสูง 153 เมตรตั้งตระหง่านอยู่ใจกลางเมือง'),
  'changzhou/comb': ('งานหัตถกรรมหวี', 'หวีจากฉางโจวที่มีประวัติศาสตร์ยาวนานนับพันปีเคยเป็นของขวัญล้ำค่าสำหรับพระราชวัง'),
  'changzhou/canal': ('คลองต้ายวิ่นเหอ', 'ริมฝั่งคลองเป็นจุดที่ผู้คนนิยมมาเดินเล่นชมย่านเมืองเก่าและแสงไฟยามค่ำคืน'),
  'shaoxing/wine': ('เหล้าเส้าซิง', 'เหล้าข้าวสีเหลืองที่มีชื่อเสียงในการปรุงอาหารจีนแห่งนี้มีการหมักบ่มมานานนับพันปี'),
  'shaoxing/bridge': ('สะพานหินโบราณ', 'เมืองเส้าซิงที่เต็มไปด้วยลำคลองยังคงอนุรักษ์สะพานหินโค้งไว้หลายร้อยแห่ง'),
  'shaoxing/pen': ('แหล่งกำเนิดอักษรวิจิตร', 'ศาลาหลานถิงของปรมาจารย์หวังซีจือถือเป็นสถานที่ศักดิ์สิทธิ์ของศิลปะการเขียนพู่กันจีน'),
  'shaoxing/boat': ('เรืออูเผิง', 'เรือพายหลังคาดำที่ใช้เท้าถีบเป็นพาหนะสุดคลาสสิกในการล่องไปตามลำคลอง'),
  'bengbu/shell': ('ท่าเรือไข่มุก', 'ชื่อเมืองมีความหมายว่าท่าเรือหอย ซึ่งในอดีตเคยมีชื่อเสียงโด่งดังจากการผลิตไข่มุกแม่น้ำหวย'),
  'bengbu/train': ('สถานีรถไฟเปิ่งปู้', 'เมืองนี้เติบโตขึ้นจากการเป็นจุดเชื่อมต่อสำคัญของเส้นทางรถไฟสายเหนือ-ใต้ที่ข้ามแม่น้ำหวย'),
  'bengbu/river': ('แม่น้ำหวย', 'แม่น้ำสายสำคัญที่ถือเป็นเส้นแบ่งเขตทางภูมิศาสตร์ระหว่างจีนเหนือและจีนใต้ไหลผ่านที่นี่'),
  'bengbu/blossom': ('เทศกาลชมดอกไม้', 'ในช่วงฤดูใบไม้ผลิ สวนสาธารณะริมแม่น้ำจะเต็มไปด้วยสีสันของงานเทศกาลชมดอกไม้'),
  'jiujiang/mountain': ('เขาหลูซาน', 'ยอดเขาที่ปกคลุมด้วยสายหมอกของเขาหลูซานได้รับการขึ้นทะเบียนเป็นมรดกโลกและเป็นแรงบันดาลใจให้แก่กวีและจิตรกรมากมาย'),
  'jiujiang/tea': ('ชาอวิ๋นอู้', 'ชาอวิ๋นอู้ที่ปลูกบนไหล่เขาหลูซานถือเป็นหนึ่งในชาที่มีรสชาติละเมียดละไมที่สุดของจีน'),
  'jiujiang/lake': ('ทะเลสาบโผหยาง', 'ทะเลสาบน้ำจืดที่ใหญ่ที่สุดในจีนแห่งนี้เป็นแหล่งอาศัยของนกกระเรียนนับพันตัวในช่วงฤดูหนาว'),
  'jiujiang/scroll': ('เมืองแห่งบทกวี', 'ประตูเมืองริมแม่น้ำแห่งนี้เป็นสถานที่ที่กวีเอกอย่างไป๋จวีอี้และซูซื่อเคยมาพำนักและรังสรรค์บทกวีไว้'),
  'quanzhou/ship': ('เส้นทางสายไหมทางทะเล', 'เมืองท่าที่ยิ่งใหญ่ที่สุดในยุคกลางที่มาร์โค โปโลเรียกว่า \'จื่อตง\' แห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลก'),
  'quanzhou/mosque': ('มัสยิดชิงจิ้ง', 'มัสยิดหินที่สร้างขึ้นในปี ค.ศ. 1009 แห่งนี้เป็นหนึ่งในมัสยิดที่เก่าแก่ที่สุดในจีน'),
  'quanzhou/puppet': ('หุ่นกระบอกฉวนโจว', 'ศิลปะการเชิดหุ่นกระบอกสายของฉวนโจวเป็นมรดกทางวัฒนธรรมบนเวทีที่มีประวัติศาสตร์ยาวนานนับพันปี'),
  'quanzhou/tea': ('ชาทิกวนอิม', 'ชาอูหลงจากเมืองอันซีที่อยู่ใกล้เคียงคือชา \'พระโพธิสัตว์เหล็ก\' ที่มีชื่อเสียงโด่งดังไปทั่วโลก'),
  'shanghai/pearl': ('หอไข่มุกตะวันออก', 'หอคอยที่มีรูปทรงเป็นลูกบอลสีชมพูโดดเด่นริมแม่น้ำหวงผู่แห่งนี้คือสัญลักษณ์ของเซี่ยงไฮ้ยุคใหม่'),
  'shanghai/bund': ('เดอะบันด์', 'ย่านริมน้ำที่มีอาคารสถาปัตยกรรมเก่าแก่สะท้อนให้เห็นถึงความรุ่งเรืองของเซี่ยงไฮ้ในอดีต'),
  'shanghai/garden': ('สวนอวี้หยวน', 'สวนสไตล์จีนดั้งเดิมจากสมัยราชวงศ์หมิงที่เต็มไปด้วยโขดหินและสระน้ำ เปรียบเสมือนโอเอซิสใจกลางเมือง'),
  'shanghai/xlb': ('เสี่ยวหลงเปา', 'แป้งห่อไส้ที่อัดแน่นด้วยน้ำซุปร้อนๆ คือเมนูขึ้นชื่อที่เป็นหัวใจสำคัญของอาหารเช้าแบบเซี่ยงไฮ้'),
  'hangzhou/lake': ('ทะเลสาบซีหู', 'ทะเลสาบแห่งนี้เต็มไปด้วยทิวทัศน์ของต้นหลิว เกาะน้อยใหญ่ และสะพานโค้ง ซึ่งได้รับการยกย่องในบทกวีจีนมากที่สุด'),
  'hangzhou/tea': ('ชาหลงจิ่ง', 'ชาเขียวหลงจิ่งที่ปลูกบนเนินเขารอบทะเลสาบถือเป็นชาที่มีชื่อเสียงที่สุดของประเทศจีน'),
  'hangzhou/temple': ('วัดหลิงอิ่น', 'วัดเก่าแก่ที่มีอายุกว่า 1,700 ปีแห่งนี้มีชื่อเสียงโด่งดังจากงานแกะสลักหินและพระพุทธรูปองค์ใหญ่'),
  'hangzhou/silk': ('ตลาดผ้าไหมหางโจว', 'ผ้าไหมหางโจวมีการทอมายาวนานนับพันปีและเป็นสัญลักษณ์แห่งความมั่งคั่งของจุดเริ่มต้นเส้นทางสายไหมทางตะวันออก'),
  'chongqing/hongya': ('ถ้ำหงหยา', 'กลุ่มอาคารบ้านเรือนบนเสาเข็มที่เกาะอยู่ริมหน้าผาแห่งนี้จะส่องแสงระยิบระยับราวกับเทพนิยายเหนือแม่น้ำในยามค่ำคืน'),
  'chongqing/hotpot': ('หม่าล่าหม้อไฟฉงชิ่ง', 'หม้อไฟที่เดือดพล่านด้วยน้ำมันเผ็ดร้อนและพริกหอมชาคือจิตวิญญาณอันเร่าร้อนของเมืองแห่งขุนเขาแห่งนี้'),
  'chongqing/monorail': ('รถไฟฟ้ารางเดี่ยวฉงชิ่ง', 'รถไฟฟ้าที่วิ่งทะลุผ่านตัวอาคารเป็นภาพจำอันเป็นเอกลักษณ์ของเมืองที่สร้างขึ้นบนภูเขาแห่งนี้'),
  'chongqing/river': ('ช่องเขาแยงซี', 'ท่าเรือแห่งนี้เป็นจุดเริ่มต้นของการล่องเรือชมช่องเขาแยงซี ซึ่งเป็นจุดที่เมืองตั้งตระหง่านอยู่ตรงจุดบรรจบของแม่น้ำสองสาย'),
  'dalian/square': ('จัตุรัสซิงไห่', 'จัตุรัสกลางเมืองที่ใหญ่ที่สุดในเอเชียแห่งนี้เป็นสถานที่จัดงานเทศกาลและการแสดงต่างๆ ริมชายฝั่งทะเล'),
  'dalian/beach': ('ชายหาดต้าเหลียน', 'ด้วยอ่าวหินและอากาศที่เย็นสบายในช่วงฤดูร้อน ทำให้ต้าเหลียนเป็นเมืองตากอากาศริมทะเลที่ได้รับความนิยมมากที่สุดในภาคเหนือ'),
  'dalian/football': ('เมืองแห่งฟุตบอล', 'ต้าเหลียนเปรียบเสมือนแหล่งกำเนิดฟุตบอลของจีนและเป็นที่ตั้งของสโมสรที่ประสบความสำเร็จมากที่สุดในประเทศ'),
  'dalian/seafood': ('อาหารทะเลต้าเหลียน', 'หอยเชลล์ กุ้ง และหอยเม่นจากทะเลเหลืองที่เย็นจัดเป็นวัตถุดิบชั้นเลิศที่ประดับอยู่บนโต๊ะอาหารของเมืองนี้'),
  'shenyang/palace': ('พระราชวังมุกเดน', 'พระราชวังแห่งแรกของราชวงศ์ชิง ซึ่งเปรียบเสมือนน้องชายของพระราชวังต้องห้ามในกรุงปักกิ่ง'),
  'shenyang/tomb': ('สุสานราชวงศ์ชิง', 'สุสานทางทิศตะวันออกและทิศเหนือที่ล้อมรอบเมืองเป็นที่ฝังพระศพอันยิ่งใหญ่ของเหล่าผู้ก่อตั้งราชวงศ์'),
  'shenyang/factory': ('แหล่งกำเนิดอุตสาหกรรมหนัก', 'อุตสาหกรรมหนักของจีนเริ่มต้นขึ้นที่นี่ โดยมีโรงงานขนาดใหญ่มากมายจนได้รับฉายาว่าเป็น รูห์รแห่งตะวันออก'),
  'shenyang/dumpling': ('เกี๊ยวเหล่าเปียน', 'เกี๊ยวนึ่งสูตรเหล่าเปียนที่มีประวัติยาวนานกว่าสองร้อยปีถือเป็นเมนูขึ้นชื่อของชาวจีนภาคเหนือ'),
  'hefei/judge': ('ศาลท่านเปา', 'เปาบุ้นจิ้นผู้เป็นสัญลักษณ์แห่งความยุติธรรมถือกำเนิดที่นี่ ศาลแห่งนี้จึงเป็นสถานที่ที่สะท้อนถึงความซื่อสัตย์สุจริตของท่าน'),
  'hefei/science': ('เมืองแห่งวิทยาศาสตร์', 'ศูนย์กลางด้านเทคโนโลยีที่รวบรวมมหาวิทยาลัยและห้องปฏิบัติการชั้นนำของประเทศจีนไว้มากมาย'),
  'hefei/lake': ('ทะเลสาบเฉาหู', 'หนึ่งในห้าทะเลสาบน้ำจืดที่ใหญ่ที่สุดในจีน ซึ่งมีชื่อเสียงในเรื่องปลาขาวและปูรสเลิศ'),
  'hefei/cake': ('ขนมงาหลูโจว', 'ขนมงาสอดไส้รสหวานเป็นของว่างดั้งเดิมที่อยู่คู่กับเมืองหลูโจวมาอย่างยาวนาน'),
  'foshan/wingchun': ('มวยหย่งชุน', 'เมืองต้นกำเนิดของมวยหย่งชุน ซึ่งเป็นรากฐานวิชาการต่อสู้ของยิปมันและบรูซ ลี'),
  'foshan/lion': ('เชิดสิงโต', 'เมืองหลวงแห่งการเชิดสิงโตภาคใต้ที่เต็มไปด้วยสีสันตระการตาจากการแสดงกระโดดเสาดอกเหมย'),
  'foshan/ceramic': ('เครื่องปั้นดินเผาฉือวาน', 'เตาเผาที่มีอายุนับพันปียังคงผลิตตุ๊กตาดินเผาฉือวานที่มีชีวิตชีวาจนถึงปัจจุบัน'),
  'foshan/opera': ('งิ้วกวางตุ้ง', 'ศิลปะการแสดงบนเวทีที่เป็นที่รักที่สุดของชาวจีนภาคใต้ได้เติบโตและรุ่งเรืองขึ้นบนแผ่นดินแห่งนี้'),
  'guiyang/pavilion': ('หอเจี่ยซิ่ว', 'หอคอยสามชั้นริมแม่น้ำหนานหมิงแห่งนี้เป็นสัญลักษณ์คู่บ้านคู่เมืองกุ้ยหยางมากว่า 400 ปี'),
  'guiyang/sourfish': ('ต้มปลาซุปเปรี้ยว', 'เมนูขึ้นชื่อของกุ้ยโจวที่นำปลาไปต้มในน้ำซุปสีแดงรสเปรี้ยวจากมะเขือเทศหมัก'),
  'guiyang/waterfall': ('น้ำตกหวงกั่วซู่', 'หนึ่งในน้ำตกที่ใหญ่ที่สุดในเอเชียที่ไหลเชี่ยวกรากจนเกิดเป็นสายรุ้งงดงาม'),
  'guiyang/miao': ('วัฒนธรรมชาวม้ง', 'เทศกาลและงานปักผ้าอันประณีตของชาวม้งที่สวมเครื่องประดับเงินช่วยสร้างสีสันให้กับหมู่บ้านบนภูเขา'),
  'changchun/film': ('เมืองแห่งภาพยนตร์', 'สถานที่ตั้งของสตูดิโอที่เป็นจุดกำเนิดภาพยนตร์จีน จนได้รับฉายาว่าเป็นฮอลลีวูดแห่งตะวันออก'),
  'changchun/car': ('เมืองแห่งยานยนต์', 'เมืองหลวงแห่งอุตสาหกรรมรถยนต์ของจีนที่เป็นจุดเริ่มต้นของการผลิตรถยนต์ที่สร้างขึ้นเองภายในประเทศ'),
  'changchun/palace': ('พระราชวังหุ่นเชิด', 'พระราชวังแห่งนี้เป็นที่ประทับของจักรพรรดิองค์สุดท้ายและเป็นพยานเงียบแห่งประวัติศาสตร์อันผันผวน'),
  'changchun/snow': ('หิมะฤดูหนาว', 'ในช่วงฤดูหนาวอันยาวนาน เมืองทั้งเมืองจะส่องประกายไปด้วยประติมากรรมน้ำแข็งและลานสกี'),
  'xining/lake': ('ทะเลสาบชิงไห่', 'ทะเลสาบน้ำเค็มที่ใหญ่ที่สุดในจีนแห่งนี้มีชื่อเสียงจากทุ่งดอกเรปซีดสีเหลืองอร่ามที่ล้อมรอบในช่วงฤดูร้อน'),
  'xining/monastery': ('วัดคุมบุม', 'หนึ่งในหกวัดที่ยิ่งใหญ่ที่สุดของพุทธศาสนาแบบทิเบต ซึ่งมีชื่อเสียงโด่งดังจากการแกะสลักเนยจามรี'),
  'xining/flower': ('ดอกเรปซีด', 'ในเดือนกรกฎาคม ที่ราบสูงแห่งนี้จะถูกปกคลุมไปด้วยทุ่งดอกเรปซีดสีทองสุดลูกหูลูกตา'),
  'xining/lamb': ('เนื้อจามรีและเนื้อแกะ', 'บะหมี่ดึงมือและเนื้อแกะย่างสไตล์ชาวหุยและชาวทิเบตคือรสชาติที่เป็นเอกลักษณ์ของที่ราบสูงแห่งนี้'),
  'guilin/karst': ('เขาหินปูนแม่น้ำหลี', 'ยอดเขาหินปูนที่โผล่พ้นสายหมอกคือทิวทัศน์ที่ปรากฏอยู่บนธนบัตรใบละ 20 หยวน'),
  'guilin/elephant': ('เขางวงช้าง', 'โขดหินรูปทรงคล้ายช้างที่กำลังใช้งวงจุ่มน้ำคือสัญลักษณ์อันเป็นที่รักของเมืองนี้'),
  'guilin/terrace': ('นาขั้นบันไดหลงจี๋', 'นาขั้นบันไดสันหลังมังกรที่โอบล้อมไหล่เขาเปรียบเสมือนบันไดที่สร้างขึ้นจากหยาดเหงื่อแรงงานนานนับศตวรรษ'),
  'guilin/osmanthus': ('ดอกหอมหมื่นลี้', 'ชื่อของเมืองมีความหมายว่าป่าหอมหมื่นลี้ ซึ่งในฤดูใบไม้ร่วงเมืองทั้งเมืองจะอบอวลไปด้วยกลิ่นหอมหวานของดอกไม้ชนิดนี้'),
  'wenzhou/merchant': ('จิตวิญญาณนักธุรกิจ', 'ผู้ประกอบการชาวเวินโจวได้รับฉายาว่าเป็นชาวยิวแห่งเมืองจีน โดยพวกเขาสร้างเครือข่ายธุรกิจไปทั่วโลก'),
  'wenzhou/shoe': ('รองเท้าและเครื่องหนัง', 'รองเท้าหนังจำนวนมหาศาลที่ใช้กันทั่วโลกล้วนผลิตมาจากเมืองแห่งโรงงานอุตสาหกรรมแห่งนี้'),
  'wenzhou/mountain': ('เขาเหยียนตั่ง', 'ภูเขาแห่งนี้มีชื่อเสียงจากน้ำตกและยอดเขาที่แหลมคม จนได้รับการยกย่องว่าเป็นภูเขาแห่งแรกริมทะเล'),
  'wenzhou/seafood': ('อาหารทะเล', 'ปลาหมึก หอยเชลล์ และปลาจากทะเลจีนตะวันออกคือวัตถุดิบหลักบนโต๊ะอาหารของชาวเมือง'),
  'tangshan/memorial': ('อนุสรณ์สถานแผ่นดินไหว', 'สวนอนุสรณ์สถานเหตุการณ์แผ่นดินไหวครั้งใหญ่ในปี 1976 คือสัญลักษณ์ของการเกิดใหม่ของเมือง'),
  'tangshan/coal': ('เหมืองถ่านหินและทางรถไฟแห่งแรก', 'ที่นี่เป็นจุดกำเนิดอุตสาหกรรมสมัยใหม่ของจีน โดยเป็นที่ตั้งของเหมืองถ่านหินและทางรถไฟแห่งแรกของประเทศ'),
  'tangshan/ceramic': ('เครื่องปั้นดินเผาถังซาน', 'เมืองแห่งเครื่องลายครามทางตอนเหนือที่มีชื่อเสียงโด่งดัง โดยเฉพาะเครื่องกระเบื้องโบนไชน่าที่สวยงามและประณีต'),
  'tangshan/lake': ('สวนสาธารณะหนานหู', 'สวนสาธารณะริมทะเลสาบที่ปรับปรุงจากพื้นที่เหมืองเก่าจนกลายเป็นปอดสีเขียวที่สำคัญของเมือง'),
  'anshan/steel': ('เมืองเหล็กกล้า', 'เมืองที่เป็นศูนย์กลางอุตสาหกรรมเหล็กกล้าที่ใหญ่ที่สุดของจีน จนได้รับฉายาว่าเป็นเมืองหลวงแห่งเหล็กกล้าของประเทศ'),
  'anshan/jade': ('หยกซิ่วเหยียน', 'เมืองแห่งหยกของจีนที่เป็นที่ตั้งของงานแกะสลักหยกที่ใหญ่ที่สุดในโลก'),
  'anshan/mountain': ('เขาเชียนซาน', 'ยอดเขาศักดิ์สิทธิ์ทางตอนเหนือที่เต็มไปด้วยวัดวาอารามและทัศนียภาพของยอดเขาที่งดงามดั่งดอกบัวพันกลีบ'),
  'anshan/spring': ('น้ำพุร้อนถังกังจื่อ', 'แหล่งน้ำพุร้อนเพื่อการบำบัดที่มีประวัติศาสตร์ยาวนานนับพันปีและเคยเป็นสถานที่พักผ่อนของเหล่าจักรพรรดิในอดีต'),
  'linyi/market': ('ตลาดค้าส่งหลินอี๋', 'ศูนย์กลางการค้าส่งที่ใหญ่ที่สุดในภาคเหนือของจีน ซึ่งเป็นจุดกระจายสินค้าไปทั่วประเทศ'),
  'linyi/brush': ('บ้านเกิดปรมาจารย์พู่กัน', 'เมืองแห่งศิลปะการเขียนพู่กันจีนและเป็นบ้านเกิดของหวังซีจือ ปรมาจารย์ด้านอักษรศิลป์ผู้ยิ่งใหญ่'),
  'linyi/mountain': ('เขาเหมิงซาน', 'ภูเขาที่สูงเป็นอันดับสองของมณฑลซานตง ซึ่งเปรียบเสมือนแหล่งผลิตอากาศบริสุทธิ์และเต็มไปด้วยน้ำตกที่สวยงาม'),
  'linyi/pancake': ('แป้งทอดอี้เหมิง', 'แป้งแผ่นบางที่ทำจากข้าวโพดเป็นอาหารหลักดั้งเดิมที่อยู่คู่กับชาวเขาอี้เหมิงมาอย่างยาวนาน'),
  'cangzhou/lion': ('สิงโตเหล็ก', 'รูปปั้นสิงโตเหล็กหล่อขนาดมหึมาที่มีอายุกว่า 1,100 ปี ซึ่งถือเป็นสัญลักษณ์อันภาคภูมิใจของเมือง'),
  'cangzhou/martial': ('ศิลปะการต่อสู้', 'เมืองแห่งวิทยายุทธของจีนที่เป็นแหล่งกำเนิดของปรมาจารย์และสำนักศิลปะการต่อสู้ที่มีชื่อเสียงมากมาย'),
  'cangzhou/canal': ('คลองขุดต้ายวิ่นเหอ', 'คลองขุดปักกิ่ง-หางโจวที่ไหลผ่านตัวเมือง โดยยังคงหลงเหลือร่องรอยของท่าเรือเก่าแก่ให้เห็นจนถึงปัจจุบัน'),
  'cangzhou/jujube': ('พุทราทองคำ', 'พุทราสายพันธุ์ที่มีเปลือกบางและรสหวานฉ่ำ ซึ่งได้รับการยกย่องว่าเป็นราชาแห่งผลไม้อบแห้ง'),
  'nantong/textile': ('เมืองแห่งสิ่งทอ', 'เมืองหลวงแห่งสิ่งทอของจีนที่ส่งออกผ้าฝ้ายคุณภาพดีไปจำหน่ายทั่วโลก'),
  'nantong/mountain': ('เขาหลางซาน', 'ภูเขาศักดิ์สิทธิ์ห้ายอดที่ตั้งอยู่บริเวณปากแม่น้ำแยงซี เป็นจุดหมายปลายทางยอดนิยมสำหรับการแสวงบุญและชมทิวทัศน์'),
  'nantong/kite': ('ว่าวนกหวีด', 'ว่าวปั้นเหยาที่มีการติดตั้งนกหวีดเพื่อให้เกิดเสียงหึ่งๆ เป็นงานฝีมือดั้งเดิมอันเป็นเอกลักษณ์ของเมืองนี้'),
  'nantong/school': ('ผู้บุกเบิกการศึกษา', 'จางเจียน นักอุตสาหกรรมผู้ก่อตั้งโรงเรียนสมัยใหม่และพิพิธภัณฑ์แห่งแรกของจีนขึ้นที่เมืองนี้'),
  'taizhou/opera': ('เหมยหลานฟาง', 'เมืองนี้เป็นบ้านเกิดของเหมยหลานฟาง ปรมาจารย์ผู้เป็นตำนานแห่งงิ้วปักกิ่ง'),
  'taizhou/tea': ('น้ำชายามเช้า', 'วัฒนธรรมการรับประทานอาหารเช้าด้วยซาลาเปาและจิบน้ำชาเป็นวิถีชีวิตที่เป็นเอกลักษณ์ของชาวเมือง'),
  'taizhou/boat': ('เทศกาลเรือฉินถง', 'เทศกาลแข่งเรือที่มีฝีพายหลายร้อยคนมารวมตัวกันในช่วงฤดูใบไม้ผลิ ทำให้แม่น้ำกลับมามีชีวิตชีวาอีกครั้ง'),
  'taizhou/meatball': ('หมูสับหัวสิงโต', 'เมนูหมูสับก้อนโตเนื้อนุ่มที่ถือเป็นอาหารขึ้นชื่อระดับคลาสสิกของอาหารสไตล์หวยหยาง'),
  'jinhua/ham': ('แฮมจินหัว', 'แฮมสีแดงที่ผ่านกรรมวิธีการบ่มแบบดั้งเดิมมานานหลายศตวรรษ และมีชื่อเสียงที่สุดในประเทศจีน'),
  'jinhua/film': ('กองถ่ายภาพยนตร์เหิงเตี้ยน', 'กองถ่ายภาพยนตร์กลางแจ้งที่ใหญ่ที่สุดในโลก ซึ่งเป็นสถานที่ถ่ายทำละครย้อนยุคจำนวนนับไม่ถ้วน'),
  'jinhua/cave': ('ถ้ำซวงหลง', 'ถ้ำใต้ดินที่ต้องนั่งเรือลอดผ่านช่องหินเตี้ยๆ เข้าไป ซึ่งมอบประสบการณ์อันน่าตื่นตาตื่นใจให้แก่ผู้มาเยือน'),
  'jinhua/bridge': ('สะพานโบราณ', 'สะพานหินโค้งและเมืองริมน้ำที่สะท้อนถึงความงดงามตามแบบฉบับของภูมิภาคเจียงหนาน'),
  'wuhu/park': ('สวนสนุกฟางเท่อ', 'หนึ่งในสวนสนุกที่ใหญ่ที่สุดของจีนที่มอบความสนุกสนานตื่นเต้นให้กับครอบครัวได้ตลอดทั้งวัน'),
  'wuhu/ironart': ('ภาพวาดเหล็ก', 'งานศิลปะภาพวาดที่สร้างสรรค์จากการดัดเหล็กให้มีความอ่อนช้อย เป็นงานฝีมือที่มีประวัติยาวนานกว่า 300 ปี'),
  'wuhu/rice': ('ท่าเรือข้าว', 'เมืองริมแม่น้ำแยงซีแห่งนี้เคยเป็นตลาดค้าข้าวที่ใหญ่ที่สุดของจีนในอดีต'),
  'wuhu/river': ('ท่าเรือแม่น้ำแยงซี', 'ท่าเรือที่คึกคักแห่งนี้เปรียบเสมือนประตูสู่ทะเลของมณฑลอันฮุย'),
  'huangshan/peak': ('ภูเขาหวงซาน', 'ภูเขาที่มีชื่อเสียงที่สุดของจีนแห่งนี้โดดเด่นด้วยยอดเขาหินแกรนิต ทะเลหมอก และต้นสนรูปร่างแปลกตา'),
  'huangshan/village': ('หมู่บ้านหงชุน', 'หมู่บ้านสไตล์ฮุยที่มีกำแพงสีขาวและลำธารไหลผ่านแห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกและมีความงดงามราวกับภาพวาด'),
  'huangshan/tea': ('ชาเหมาเฟิง', 'ชาเขียวปลายยอดอ่อนที่เก็บเกี่ยวจากบนภูเขาที่มีหมอกปกคลุมแห่งนี้ เป็นหนึ่งในสิบสุดยอดชาที่มีชื่อเสียงที่สุดของจีน'),
  'huangshan/ink': ('หมึกและศิลปะหุยโจว', 'หมึกหุยโจว งานแกะสลักไม้ และศิลปะการเขียนพู่กันจีนถือเป็นสมบัติทางวัฒนธรรมอันล้ำค่าของภูมิภาคนี้'),
  'yichun/moon': ('ภูเขาหมิงเยว่', 'ภูเขาแห่งพระจันทร์สว่างที่มีชื่อเสียงในเรื่องบ่อน้ำพุร้อนและทิวทัศน์อันงดงามที่มองเห็นได้จากกระเช้าไฟฟ้า'),
  'yichun/spring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนที่อุดมไปด้วยแร่ธาตุซีลีเนียมหายากทำให้เมืองนี้กลายเป็นศูนย์กลางการแช่น้ำพุร้อนของจีน'),
  'yichun/zen': ('พุทธศาสนานิกายเซน', 'วัดบนภูเขาที่เป็นรากฐานของนิกายเซนในจีนเชื้อเชิญให้ผู้มาเยือนได้สัมผัสกับความสงบทางจิตใจ'),
  'yichun/rice': ('ที่ราบลุ่มแม่น้ำหยวนเหอ', 'ที่ราบอันอุดมสมบูรณ์แห่งนี้เป็นแหล่งเพาะปลูกข้าวที่สำคัญของมณฑลเจียงซีมาอย่างยาวนาน'),
  'zhangzhou/narcissus': ('ดอกนาร์ซิสซัส', 'แหล่งปลูกหัวดอกนาร์ซิสซัสที่มีชื่อเสียงที่สุดของจีน ซึ่งถือเป็นสัญลักษณ์แห่งเทศกาลฤดูใบไม้ผลิ'),
  'zhangzhou/tulou': ('บ้านดินถู่โหลว', 'ป้อมปราการดินอัดทรงกลมขนาดใหญ่ที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกแห่งนี้ เป็นที่อยู่อาศัยที่รวมผู้คนทั้งหมู่บ้านไว้ใต้หลังคาเดียวกัน'),
  'zhangzhou/banana': ('ผลไม้เมืองร้อน', 'สวนกล้วย ลำไย และส้มเขียวหวาน ช่วยให้พื้นที่สามเหลี่ยมปากแม่น้ำแห่งนี้เขียวชอุ่มตลอดทั้งปี'),
  'zhangzhou/coast': ('เกาะตงซาน', 'เกาะที่เป็นดั่งไข่มุกแห่งชายฝั่งทางใต้ โดดเด่นด้วยหาดทรายสีทองและหมู่บ้านชาวประมง'),
  'guangzhou/tower': ('หอกวางเจา', 'หอคอยที่สูงที่สุดแห่งหนึ่งของโลกซึ่งมีรูปร่างเพรียวบางและประดับประดาด้วยแสงสีในยามค่ำคืน'),
  'guangzhou/dimsum': ('ติ่มซำ', 'การดื่มชาและทานติ่มซำที่นึ่งในเข่งไม้ไผ่ถือเป็นหัวใจสำคัญของวัฒนธรรมการกินแบบกวางตุ้ง'),
  'guangzhou/academy': ('ตระกูลเฉิน', 'หอประชุมตระกูลเฉินเป็นผลงานชิ้นเอกของงานฝีมือชาวกวางตุ้งที่โดดเด่นด้วยงานแกะสลักไม้และเครื่องปั้นดินเผา'),
  'guangzhou/flower': ('นครแห่งดอกไม้', 'กวางโจวได้รับฉายาว่านครแห่งดอกไม้เพราะมีดอกไม้บานสะพรั่งตลอดปีและมีการจัดงานเทศกาลดอกไม้อย่างยิ่งใหญ่ในช่วงปีใหม่'),
  'wuhan/crane': ('หอเหลือง', 'หอคอยเก่าแก่พันปีที่ตั้งตระหง่านริมแม่น้ำแยงซีแห่งนี้เป็นแรงบันดาลใจให้แก่บทกวีจีนที่มีชื่อเสียงมากมาย'),
  'wuhan/noodle': ('บะหมี่แห้งงา', 'บะหมี่แห้งคลุกซอสงาเป็นอาหารเช้าที่ขาดไม่ได้ของชาวอู่ฮั่น'),
  'wuhan/duckneck': ('คอเป็ดพะโล้รสเผ็ด', 'คอเป็ดพะโล้รสจัดจ้านเป็นของว่างยอดนิยมที่ชาวเมืองมักซื้อมาทานระหว่างนั่งพูดคุยกันในยามค่ำคืน'),
  'wuhan/university': ('ซากุระมหาวิทยาลัยอู่ฮั่น', 'ดอกซากุระที่บานสะพรั่งภายในมหาวิทยาลัยอู่ฮั่นดึงดูดนักท่องเที่ยวหลายพันคนให้มาเยี่ยมชมในทุกฤดูใบไม้ผลิ'),
  'tianjin/eye': ('เทียนจินอาย', 'ชิงช้าสวรรค์ที่สร้างอยู่บนสะพานแห่งนี้ช่วยให้มองเห็นทิวทัศน์ของแม่น้ำทั้งสองฝั่งได้อย่างชัดเจน'),
  'tianjin/baozi': ('ซาลาเปาโกวปู้หลี่', 'ซาลาเปาไส้หมูจีบสวยที่เป็นเมนูขึ้นชื่อของเมืองเทียนจินมานานกว่า 150 ปี'),
  'tianjin/crosstalk': ('เซี่ยงเซิง', 'ศิลปะการแสดงตลกพูดคุยสองคนที่เป็นประเพณีดั้งเดิมของเทียนจินซึ่งมีต้นกำเนิดมาจากโรงน้ำชา'),
  'tianjin/architecture': ('ย่านสถาปัตยกรรมยุโรป', 'กลุ่มวิลล่าสไตล์ยุโรปในย่านถนนสายหลักทั้งห้าทำให้เทียนจินได้รับฉายาว่าเป็นพิพิธภัณฑ์สถาปัตยกรรม'),
  'xiamen/island': ('เกาะกูลั่งอวี่', 'เกาะที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกแห่งนี้เป็นเสมือนพิพิธภัณฑ์กลางแจ้งที่เต็มไปด้วยวิลล่าสไตล์โคโลเนียลและถนนที่ห้ามรถยนต์วิ่ง'),
  'xiamen/piano': ('เกาะเปียโน', 'เกาะกูลั่งอวี่ได้รับฉายาว่าเกาะเปียโนเนื่องจากมีจำนวนเปียโนต่อประชากรสูงที่สุดแห่งหนึ่งของโลก'),
  'xiamen/egret': ('นกยางขาว', 'นกยางขาวเป็นสัญลักษณ์ประจำเมืองที่สะท้อนถึงชื่อเรียกในอดีตของเมืองนี้ว่าเกาะนกยาง'),
  'xiamen/oyster': ('หอยทอด', 'หอยทอดกรอบนอกนุ่มในที่ทำจากหอยนางรมสดและไข่ไก่ถือเป็นเมนูเด็ดของอาหารทะเลท้องถิ่น'),
  'harbin/ice': ('เทศกาลน้ำแข็งฮาร์บิน', 'เทศกาลฤดูหนาวที่มีการจัดแสดงปราสาทน้ำแข็งขนาดมหึมาประดับไฟสวยงามซึ่งถือว่ายิ่งใหญ่ที่สุดในโลก'),
  'harbin/cathedral': ('มหาวิหารเซนต์โซเฟีย', 'มหาวิหารนิกายออร์ทอดอกซ์ที่มีโดมรูปหัวหอมแห่งนี้เป็นสัญลักษณ์ที่สะท้อนถึงอดีตอันรุ่งเรืองในแบบยุโรปของเมืองฮาร์บิน'),
  'harbin/sausage': ('ไส้กรอกแดง', 'ไส้กรอกรมควันสไตล์รัสเซียสีแดงสดเป็นอาหารขึ้นชื่อที่มีประวัติศาสตร์ยาวนานกว่าร้อยปีของเมืองนี้'),
  'harbin/accordion': ('เมืองแห่งดนตรี', 'ด้วยมรดกทางวัฒนธรรมจากรัสเซีย ฮาร์บินจึงเป็นเมืองที่ก่อตั้งวงดนตรีซิมโฟนีออร์เคสตราวงแรกของจีน'),
  'fuzhou/alley': ('ซานฟางชีเซี่ยง', 'ย่านเมืองเก่าที่มีกำแพงสีขาวและหลังคาสีดำแห่งนี้เปรียบเสมือนพิพิธภัณฑ์ที่มีชีวิตซึ่งจัดแสดงสถาปัตยกรรมในยุคราชวงศ์หมิงและชิง'),
  'fuzhou/banyan': ('เมืองแห่งต้นไทร', 'ต้นไทรยักษ์โบราณที่แผ่กิ่งก้านให้ร่มเงาไปทั่วถนนทำให้ฝูโจวได้รับฉายาว่าเป็นเมืองแห่งต้นไทร'),
  'fuzhou/hotspring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนที่ผุดขึ้นมากลางเมืองฝูโจวถูกนำมาใช้ในโรงอาบน้ำสาธารณะมานานนับพันปี'),
  'fuzhou/soup': ('พระกระโดดกำแพง', 'ซุปเลิศรสที่เคี่ยวจากวัตถุดิบชั้นเลิศหลายสิบชนิดนี้ถือเป็นสุดยอดเมนูอาหารขึ้นชื่อของมณฑลฝูเจี้ยน'),
  'dongguan/robot': ('โรงงานของโลก', 'ตงกวนเป็นฐานการผลิตอุปกรณ์อิเล็กทรอนิกส์ขนาดใหญ่ของโลกด้วยระบบโรงงานอัตโนมัติที่ทันสมัย'),
  'dongguan/basketball': ('เมืองแห่งบาสเกตบอล', 'ตงกวนเป็นที่ตั้งของสโมสรบาสเกตบอลที่ประสบความสำเร็จมากที่สุดในประเทศจีน'),
  'dongguan/keyuan': ('สวนเข่อหยวน', 'หนึ่งในสี่สวนคลาสสิกที่มีชื่อเสียงที่สุดของมณฑลกวางตุ้ง ซึ่งโดดเด่นด้วยสระน้ำและศาลาที่สวยงาม'),
  'dongguan/cannon': ('ป้อมปราการหู่เหมิน', 'ป้อมปราการหู่เหมินเป็นจุดเริ่มต้นของสงครามฝิ่นและเป็นสถานที่ประวัติศาสตร์ที่เคยมีการเผาฝิ่นทิ้ง'),
  'lanzhou/beefnoodle': ('บะหมี่เนื้อหลานโจว', 'ด้วยน้ำซุปเนื้อใสและเส้นที่นวดด้วยมือ ทำให้หลานโจวกลายเป็นเมืองหลวงแห่งบะหมี่ของจีน'),
  'lanzhou/waterwheel': ('กังหันน้ำ', 'กังหันน้ำขนาดใหญ่ริมแม่น้ำเหลืองเป็นสัญลักษณ์ของภูมิปัญญาด้านวิศวกรรมชลประทานที่มีมานานหลายศตวรรษ'),
  'lanzhou/statue': ('อนุสาวรีย์มารดาแม่น้ำเหลือง', 'รูปปั้นแม่และลูกที่ตั้งอยู่ริมฝั่งแม่น้ำเป็นตัวแทนของสายน้ำที่หล่อเลี้ยงอารยธรรมจีนมาอย่างยาวนาน'),
  'lanzhou/raft': ('แพหนังแกะ', 'แพแบบดั้งเดิมที่ทำจากหนังแกะพองลมยังคงล่องลอยอยู่ในแม่น้ำเหลืองจนถึงทุกวันนี้'),
  'urumqi/bazaar': ('ตลาดแกรนด์บาซาร์', 'ตลาดแห่งนี้เต็มไปด้วยหอคอยสูงและร้านขายเครื่องเทศที่สะท้อนสีสันแห่งเส้นทางสายไหมได้อย่างชัดเจน'),
  'urumqi/tianshan': ('ทะเลสาบเทียนฉือ', 'ทะเลสาบเทียนฉือตั้งอยู่ใต้เทือกเขาหิมะเทียนซานและรายล้อมไปด้วยป่าสนอันเขียวขจี'),
  'urumqi/kebab': ('เนื้อแกะย่าง', 'เนื้อแกะเสียบไม้ย่างบนเตาถ่านที่ปรุงรสด้วยเครื่องเทศเป็นเมนูสำคัญบนโต๊ะอาหารของชาวอุยกูร์'),
  'urumqi/dance': ('ระบำอุยกูร์', 'การร่ายรำหมุนตัวของชาวอุยกูร์ที่ประกอบด้วยเสียงกลองและเครื่องดนตรีราวัปช่วยสร้างสีสันให้กับทุกงานเฉลิมฉลอง'),
  'haikou/coconut': ('เมืองแห่งมะพร้าว', 'ถนนหนทางที่เรียงรายไปด้วยต้นมะพร้าวทำให้ไหโข่วได้รับสมญานามว่าเป็นเมืองแห่งมะพร้าว'),
  'haikou/arcade': ('ตึกแถวฉีโหลว', 'อาคารสถาปัตยกรรมแบบฉีโหลวที่มีทางเดินใต้ถุนตึกช่วยสร้างบรรยากาศถนนที่มีร่มเงาในเขตภาคใต้'),
  'haikou/crater': ('อุทยานภูเขาไฟ', 'ปากปล่องภูเขาไฟที่ดับแล้วกลายเป็นอุทยานธรณีวิทยาอันเขียวชอุ่มบริเวณชานเมือง'),
  'haikou/turtle': ('ทะเลเขตร้อน', 'น้ำทะเลที่ใสสะอาดและแนวปะการังที่อุดมสมบูรณ์ทำให้ชายฝั่งแห่งนี้เป็นบ้านของเต่าทะเล'),
  'luoyang/grotto': ('ถ้ำหินหลงเหมิน', 'พระพุทธรูปนับหมื่นองค์ที่สลักลงบนหน้าผาถือเป็นสมบัติทางศิลปะที่ได้รับการขึ้นทะเบียนเป็นมรดกโลก'),
  'luoyang/peony': ('เมืองหลวงแห่งดอกโบตั๋น', 'ดอกโบตั๋นนับพันต้นที่บานสะพรั่งในเดือนเมษายนทำให้ลั่วหยางได้รับฉายาว่าเป็นเมืองหลวงแห่งดอกโบตั๋น'),
  'luoyang/whitehorse': ('วัดม้าขาว', 'วัดแห่งนี้ก่อตั้งขึ้นในปี ค.ศ. 68 และได้รับการยกย่องว่าเป็นวัดพุทธแห่งแรกของจีน'),
  'luoyang/capital': ('เมืองหลวงเก่า', 'ลั่วหยางเคยเป็นเมืองหลวงของ 13 ราชวงศ์และถือเป็นแหล่งกำเนิดสำคัญของอารยธรรมจีน'),
  'shantou/gongfutea': ('ชาฉาซานกังฟู', 'พิธีชงชาในถ้วยใบเล็กแบบฉาซานถือเป็นศิลปะแห่งการต้อนรับแขกผู้มาเยือน'),
  'shantou/beefpot': ('หม้อไฟเนื้อ', 'หม้อไฟสไตล์ฉาซานที่ขึ้นชื่อเรื่องเนื้อวัวสดสไลด์บางที่ลวกสุกในเวลาเพียงไม่กี่วินาที'),
  'shantou/opera': ('งิ้วแต้จิ๋ว', 'งิ้วแต้จิ๋วที่มีประวัติยาวนานกว่า 600 ปีโดดเด่นด้วยท่วงทำนองที่อ่อนช้อยและเครื่องแต่งกายที่ปักลวดลายอย่างประณีต'),
  'shantou/harbor': ('เมืองท่าซัวเถา', 'เมืองท่าที่เป็นบ้านเกิดของชาวจีนโพ้นทะเลจำนวนมากและเป็นประตูการค้าทางทะเลที่สำคัญมาตั้งแต่อดีต'),
  'baoding/mansion': ('จวนผู้ว่าการเป่าติ้ง', 'สถานที่ทำการระดับมณฑลที่สำคัญที่สุดในสมัยราชวงศ์ชิง ซึ่งยังคงสภาพความสมบูรณ์ของสถาปัตยกรรมไว้ได้เป็นอย่างดี'),
  'baoding/donkeyburger': ('เบอร์เกอร์เนื้อลา', 'เนื้อลาปรุงรสยัดไส้ในแป้งทอดกรอบที่เป็นเมนูสตรีทฟู้ดขึ้นชื่อของภูมิภาคนี้'),
  'baoding/balls': ('ลูกบอลบริหารมือ', 'ลูกบอลโลหะสำหรับหมุนในอุ้งมือเพื่อบริหารกล้ามเนื้อ เป็นภูมิปัญญาการดูแลสุขภาพที่มีมานานหลายศตวรรษ'),
  'baoding/reeds': ('พื้นที่ชุ่มน้ำไป๋หยางเตี้ยน', 'พื้นที่ชุ่มน้ำขนาดใหญ่ที่สุดทางตอนเหนือของจีน เป็นสวรรค์ของนกนานาชนิดท่ามกลางดงต้นอ้อและดอกบัว'),
  'jilin/rime': ('ปรากฏการณ์เหมยฮัว (เหมยฮัวซู่)', 'เกล็ดน้ำแข็งสีขาวที่เกาะตามกิ่งไม้ริมแม่น้ำซงฮัวถือเป็นหนึ่งในสี่สิ่งมหัศจรรย์ทางธรรมชาติของจีน'),
  'jilin/snowboard': ('ลานสกีจี๋หลิน', 'ด้วยปริมาณหิมะที่หนานุ่มและฤดูกาลที่ยาวนาน ทำให้ที่นี่เป็นหนึ่งในจุดหมายปลายทางยอดนิยมสำหรับการเล่นสกีทางตอนเหนือ'),
  'jilin/meteorite': ('พิพิธภัณฑ์อุกกาบาต', 'สถานที่จัดแสดงอุกกาบาตหินที่มีขนาดใหญ่ที่สุดในโลก ซึ่งตกลงมายังโลกเมื่อปี ค.ศ. 1976'),
  'jilin/skate': ('แม่น้ำซงฮัวในฤดูหนาว', 'แม่น้ำซงฮัวที่กลายเป็นน้ำแข็งในช่วงฤดูหนาวจะกลายเป็นลานสเก็ตธรรมชาติสำหรับผู้ที่มาเล่นสเก็ตและเดินเล่น'),
  'ordos/khan': ('สุสานเจงกีสข่าน', 'สุสานอันยิ่งใหญ่ที่สร้างขึ้นเพื่อรำลึกถึงวีรบุรุษแห่งทุ่งหญ้าอย่างเจงกีสข่าน ซึ่งถือเป็นหัวใจสำคัญของวัฒนธรรมมองโกล'),
  'ordos/cashmere': ('ผ้าแคชเมียร์', 'ผ้าแคชเมียร์ที่ทอจากขนแพะในเมืองออร์ดอสมีชื่อเสียงระดับโลกในอุตสาหกรรมสิ่งทอ'),
  'ordos/sanddune': ('เนินทรายร้องเพลง', 'เนินทรายขนาดใหญ่ในทะเลทรายคูบูฉีที่จะส่งเสียงครางเมื่อเราสไลด์ตัวลงมา ถือเป็นจุดท่องเที่ยวที่ได้รับความนิยมมาก'),
  'ordos/yurt': ('กระโจมมองโกล', 'กระโจมผ้าสักหลาดสีขาวที่ตั้งอยู่บนทุ่งหญ้าอันกว้างใหญ่เป็นสัญลักษณ์ของการใช้ชีวิตแบบเร่ร่อน'),
  'jining/confucius': ('ศาลขงจื๊อ', 'ศาลเจ้า คฤหาสน์ และสุสานของขงจื๊อในเมืองชวีฟู่ที่อยู่ใกล้เคียง ได้รับการขึ้นทะเบียนเป็นมรดกโลกโดยองค์การยูเนสโก'),
  'jining/barge': ('คลองต้ายวิ่นเหอ', 'เมืองจี่หนิงเคยเป็นเมืองท่าที่คึกคักและเป็นศูนย์กลางทางวัฒนธรรมบนเส้นทางคลองปักกิ่ง-หางโจว'),
  'jining/sword': ('วีรบุรุษแห่งเขาเหลียงซาน', 'เหล่าจอมยุทธ์ผู้กล้าทั้ง 108 คนจากวรรณกรรมคลาสสิกเรื่องซ้องกั๋งได้มารวมตัวกันที่เนินเขาแห่งนี้'),
  'jining/fishnet': ('ทะเลสาบเวยซาน', 'ชาวประมงยังคงใช้วิธีจับปลาแบบดั้งเดิมบนทะเลสาบดอกบัวที่ใหญ่ที่สุดทางตอนเหนือของจีน'),
  'langfang/culture': ('ศูนย์วัฒนธรรมเส้นทางสายไหม', 'ศูนย์วัฒนธรรมสมัยใหม่ขนาดใหญ่ของเมืองที่รวบรวมศิลปะจากเส้นทางสายไหมไว้ในที่เดียว'),
  'langfang/furniture': ('เมืองเฟอร์นิเจอร์', 'อำเภอเซียงเหอที่อยู่ใกล้เคียงเป็นหนึ่งในศูนย์กลางการผลิตและซื้อขายเฟอร์นิเจอร์ที่ใหญ่ที่สุดของจีน'),
  'langfang/tunnel': ('อุโมงค์สงครามโบราณ', 'อุโมงค์ทหารใต้ดินที่มีอายุนับพันปีถูกขุดขึ้นเพื่อใช้เป็นแนวป้องกันชายแดนในสมัยก่อน'),
  'langfang/themepark': ('สวนสนุกหมายเลขหนึ่ง', 'สวนสนุกขนาดใหญ่ที่จำลองเมืองโบราณล้อมรอบด้วยกำแพงเมืองพร้อมต้อนรับนักท่องเที่ยวทุกครอบครัว'),
  'yancheng/salt': ('เมืองแห่งเกลือ', 'ชื่อของเมืองมีความหมายว่าป้อมปราการเกลือ ซึ่งเคยเป็นศูนย์กลางการผลิตเกลือที่สำคัญของจีนมานานหลายศตวรรษ'),
  'yancheng/crane': ('นกกระเรียนมงกุฎแดง', 'พื้นที่ชุ่มน้ำชายฝั่งแห่งนี้เป็นแหล่งอาศัยในช่วงฤดูหนาวที่ใหญ่ที่สุดในโลกของนกกระเรียนมงกุฎแดงตามธรรมชาติ'),
  'yancheng/elk': ('กวางมิลู', 'กวางมิลูที่เคยสูญพันธุ์ไปจากธรรมชาติได้ถูกเพาะพันธุ์จนกลับมามีชีวิตอีกครั้งในพื้นที่ชุ่มน้ำแห่งนี้'),
  'yancheng/wetland': ('พื้นที่ชุ่มน้ำชายฝั่ง', 'หาดเลนที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกโดยยูเนสโกแห่งนี้เป็นจุดแวะพักสำคัญของนกอพยพทั่วโลก'),
  'huzhou/brush': ('พู่กันหูโจว', 'พู่กันหูโจวเป็นหนึ่งในสี่สมบัติล้ำค่าของการเขียนพู่กันจีนที่ผลิตขึ้นที่นี่'),
  'huzhou/bamboo': ('ป่าไผ่อันจี๋', 'ป่าไผ่สีเขียวขจีสุดลูกหูลูกตาที่เป็นแรงบันดาลใจให้กับภาพยนตร์หลายเรื่องและช่วยให้อากาศเย็นสบาย'),
  'huzhou/silkworm': ('ไหม', 'ชายฝั่งทางตอนใต้ของทะเลสาบไท่หูเป็นศูนย์กลางการผลิตผ้าไหมจากหม่อนไหมมานานนับพันปี'),
  'huzhou/whitetea': ('ชาขาวอันจี๋', 'ชาขาวอันจี๋มีใบชาสีซีดและรสชาติหวานละมุน ถือเป็นหนึ่งในชาที่หายากที่สุดของจีน'),
  'quzhou/go': ('หมากล้อม', 'เมืองแห่งนี้ได้รับการยกย่องว่าเป็นดินแดนแห่งหมากล้อมตามตำนานเล่าขานเกี่ยวกับภูเขาหลานเคอ'),
  'quzhou/peaks': ('ภูเขาเจียงหลาง', 'ยอดเขาหินยักษ์สามลูกที่ตั้งตระหง่านเสียดฟ้าเป็นทัศนียภาพอันเป็นเอกลักษณ์ระดับมรดกโลก'),
  'quzhou/ponkan': ('ส้มพอนคังเมืองฉูโจว', 'ส้มพอนคังรสหวานเปลือกบางเป็นของขวัญจากเนินเขาในช่วงฤดูหนาว'),
  'quzhou/cake': ('ขนมปังแผ่นอบ', 'ขนมปังแผ่นโรยงาที่อบจนกรอบบนผนังเตาเป็นอาหารเช้าแบบดั้งเดิมของท้องถิ่น'),
  'huainan/tofu': ('ต้นกำเนิดเต้าหู้', 'เต้าหู้ถูกคิดค้นขึ้นบนเขาปากงเมื่อ 2,000 ปีก่อน และกลายเป็นวัตถุดิบสำคัญของอาหารทั่วโลกจากที่นี่'),
  'huainan/coalmine': ('เมืองแห่งถ่านหิน', 'เมืองหวยหนานเป็นแหล่งพลังงานสำคัญของจีนตะวันออกเนื่องจากมีแหล่งถ่านหินที่อุดมสมบูรณ์'),
  'huainan/oldtown': ('เมืองเก่าโช่วเซี่ยน', 'กำแพงเมืองยุคราชวงศ์ซ่งที่ยังคงสภาพสมบูรณ์เป็นตัวอย่างที่หาได้ยากของการออกแบบป้อมปราการโบราณ'),
  'huainan/classic': ('คัมภีร์หวยหนานจื่อ', 'คัมภีร์ปรัชญาที่รวบรวมโดยเจ้าชายหลิวอันถูกเรียบเรียงขึ้นบนแผ่นดินแห่งนี้'),
  'jingdezhen/porcelain': ('เมืองหลวงแห่งเครื่องปั้นดินเผา', 'เมืองนี้เป็นแหล่งผลิตเครื่องกระเบื้องสำหรับราชสำนักมานานนับพันปีจนได้รับการขนานนามว่าเป็นเมืองหลวงแห่งเครื่องปั้นดินเผาของโลก'),
  'jingdezhen/kiln': ('เตาเผาโบราณ', 'เตาเผามังกรที่ใช้ฟืนเป็นเชื้อเพลิงยังคงสืบทอดศิลปะการผลิตเครื่องกระเบื้องแบบดั้งเดิมให้คงอยู่ต่อไป'),
  'jingdezhen/bluewhite': ('เครื่องกระเบื้องลายคราม', 'เครื่องกระเบื้องสีขาวลวดลายสีน้ำเงินจากแร่โคบอลต์เป็นเอกลักษณ์ที่โด่งดังไปทั่วโลกของเมืองนี้'),
  'jingdezhen/painting': ('จิตรกรรมบนเครื่องกระเบื้อง', 'เครื่องกระเบื้องที่วาดลวดลายด้วยพู่กันอย่างประณีตโดยศิลปินชั้นครูนั้นมีคุณค่าไม่ต่างจากภาพวาดชั้นเลิศ'),
  'jian/jinggang': ('เทือกเขาจิ่งกัง', 'เทือกเขาที่ปกคลุมด้วยสายหมอกแห่งนี้เป็นฐานที่มั่นแห่งแรกของการปฏิวัติและเป็นหัวใจสำคัญของการท่องเที่ยวเชิงประวัติศาสตร์'),
  'jian/torch': ('ประกายไฟแห่งการปฏิวัติ', 'ดินแดนที่เป็นจุดกำเนิดของแนวคิดที่ว่าประกายไฟเพียงจุดเดียวก็สามารถเผาผลาญทุ่งหญ้าได้ทั้งผืนแห่งนี้เป็นอนุสรณ์สถานทางประวัติศาสตร์ที่สำคัญ'),
  'jian/academy': ('สำนักศึกษาไป๋ลู่โจว', 'สำนักศึกษาเก่าแก่อายุนับพันปีบนเกาะกลางแม่น้ำก้านแห่งนี้เคยเป็นสถานที่บ่มเพาะบัณฑิตสอบเข้ารับราชการมาแล้วนับไม่ถ้วน'),
  'jian/pine': ('สนจิ่งกัง', 'ต้นสนที่เติบโตท่ามกลางสายหมอกเป็นสัญลักษณ์ของจิตวิญญาณแห่งขุนเขาและความทรหดอดทน'),
  'nanping/wuyi': ('ภูเขาอู่อี๋', 'ภูเขาที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกจากยูเนสโกแห่งนี้มีหน้าผาสีแดงและหุบเขาสีเขียวขจี ถือเป็นขุมทรัพย์ทางธรรมชาติและวัฒนธรรมอันล้ำค่า'),
  'nanping/rocktea': ('ชาต้าหงเผา', 'ชาอูหลงต้าหงเผาที่ปลูกบนหน้าผาแห่งนี้จัดเป็นหนึ่งในชาที่แพงที่สุดในโลก'),
  'nanping/bambooraft': ('ล่องแพเก้าโค้ง', 'นักท่องเที่ยวจะได้ล่องแพไม้ไผ่ไปตามลำธารเก้าโค้งที่ไหลผ่านระหว่างหน้าผาสีแดง'),
  'nanping/scholar': ('จูซี', 'จูซี ผู้ก่อตั้งลัทธิขงจื๊อใหม่ เคยสอนหนังสืออยู่ที่เชิงเขาแห่งนี้'),
  'shenzhen/skyscraper': ('ตึกระฟ้า', 'ป่าตึกระฟ้าที่ผงาดขึ้นจากหมู่บ้านชาวประมงภายใน 40 ปีนี้คือปาฏิหาริย์แห่งการปฏิรูปของจีน'),
  'shenzhen/chip': ('ซิลิคอนแวลลีย์แห่งจีน', 'ด้วยตลาดอิเล็กทรอนิกส์หัวเฉียงเป่ยและบริษัทเทคโนโลยียักษ์ใหญ่ เซินเจิ้นจึงได้ชื่อว่าเป็น “ซิลิคอนแวลลีย์แห่งจีน”'),
  'shenzhen/miniature': ('หน้าต่างโลก', 'สวนสนุกที่รวบรวมสิ่งก่อสร้างจำลองจากสถานที่สำคัญทั่วโลกแห่งนี้เป็นสัญลักษณ์ของเมืองเซินเจิ้น'),
  'shenzhen/mangrove': ('อ่าวเซินเจิ้น', 'อ่าวที่เต็มไปด้วยป่าชายเลนแห่งนี้เป็นแหล่งอาศัยของนกอพยพและนกกระยาง'),
  'xian/terracotta': ('กองทัพทหารดินเผา', 'ทหารดินเผานับพันนายที่เฝ้าสุสานจักรพรรดิจิ๋นซีได้รับการขนานนามว่าเป็นสิ่งมหัศจรรย์อันดับแปดของโลก'),
  'xian/citywall': ('กำแพงเมืองซีอาน', 'กำแพงเมืองสมัยราชวงศ์หมิงที่ได้รับการอนุรักษ์ไว้อย่างดีที่สุดของจีนแห่งนี้สามารถปั่นจักรยานชมได้ตามแนวกำแพง'),
  'xian/drumtower': ('หอระฆัง', 'หอระฆังสมัยราชวงศ์หมิงที่ตั้งอยู่ใจกลางเมืองแห่งนี้เป็นสัญลักษณ์ของเมืองหลวงโบราณ'),
  'xian/roujiamo': ('โร่วเจียหมัว', 'โร่วเจียหมัวคือเบอร์เกอร์ต้นตำรับแห่งเส้นทางสายไหม เป็นขนมปังแบนกรอบสอดไส้เนื้อปรุงรส'),
  'suzhou/garden': ('สวนโบราณซูโจว', 'สวนที่ได้รับการขึ้นทะเบียนเป็นมรดกโลกจากยูเนสโกแห่งนี้ได้รับการออกแบบอย่างประณีตด้วยสวนหิน บ่อน้ำ และศาลา'),
  'suzhou/watertown': ('เวนิสแห่งตะวันออก', 'ด้วยคลอง สะพานหิน และบ้านเรือนสีขาว ซูโจวจึงได้รับสมญานามว่า “เวนิสแห่งตะวันออก”'),
  'suzhou/embroidery': ('ผ้าปักซู', 'ผ้าปักไหมสองหน้าเป็นงานฝีมือเก่าแก่ของซูโจวที่มีอายุยาวนานนับพันปี'),
  'suzhou/kunqu': ('งิ้วคุนฉวี่', 'งิ้วคุนฉวี่อันสง่างาม ซึ่งได้รับการยกย่องว่าเป็นมารดาแห่งงิ้วจีนทั้งปวง มีต้นกำเนิดที่นี่'),
  'kunming/stoneforest': ('ป่าหิน', 'เสาหินปูนขนาดยักษ์ที่ถูกกัดเซาะมานานหลายล้านปี ก่อให้เกิดเขาวงกตหินที่น่าพิศวง'),
  'kunming/springcity': ('นครแห่งฤดูใบไม้ผลิ', 'ด้วยสภาพอากาศที่อบอุ่นตลอดทั้งปี คุนหมิงจึงเป็น \'นครแห่งฤดูใบไม้ผลิ\' ที่ดอกไม้ไม่เคยโรยรา'),
  'kunming/seagull': ('นกนางนวลหัวดำ', 'ทุกฤดูหนาว นกนางนวลหลายพันตัวจากไซบีเรียจะบินมายังริมทะเลสาบจนกลายเป็นสีขาวโพลน'),
  'kunming/ricenoodle': ('ก๋วยเตี๋ยวข้ามสะพาน', 'ก๋วยเตี๋ยวเส้นเล็กที่ใส่ลงในน้ำซุปร้อนๆ ที่โต๊ะ เป็นอาหารขึ้นชื่อของยูนนาน'),
  'jinan/spring': ('นครแห่งน้ำพุ', 'น้ำพุที่มีชื่อเสียง 72 แห่งที่ผุดขึ้นจากพื้นดิน ทำให้เมืองจี่หนานได้ชื่อว่าเป็น \'นครแห่งน้ำพุ\''),
  'jinan/daminglake': ('ทะเลสาบต้าหมิง', 'ทะเลสาบใจกลางเมืองแห่งนี้ล้อมรอบด้วยต้นหลิวและดอกบัว และได้รับน้ำจากน้ำพุต่างๆ'),
  'jinan/buddhamountain': ('ภูเขาพันพระพุทธรูป', 'ด้วยพระพุทธรูปหลายร้อยองค์ที่แกะสลักอยู่บนเนินเขา ภูเขาแห่งนี้จึงเป็นสถานที่แสวงบุญ'),
  'jinan/poet': ('หลี่ ชิงจ้าว', 'หลี่ ชิงจ้าว กวีหญิงผู้ยิ่งใหญ่ที่สุดของจีน ถือกำเนิดในนครแห่งน้ำพุแห่งนี้'),
  'ningbo/library': ('หอสมุดเทียนอี', 'หอสมุดเทียนอีที่มีอายุ 450 ปี เป็นห้องสมุดส่วนตัวที่เก่าแก่ที่สุดที่ยังคงอยู่ของเอเชีย'),
  'ningbo/port': ('ท่าเรือขนส่งสินค้า', 'ท่าเรือหนิงโป-โจวซานเป็นท่าเรือที่คึกคักที่สุดในโลกในด้านปริมาณสินค้า'),
  'ningbo/tangyuan': ('ทังหยวน', 'ทังหยวน หรือขนมบัวลอยไส้งาดำ เป็นของหวานขึ้นชื่อของเมืองนี้'),
  'ningbo/seafood': ('อาหารทะเล', 'ปลาจวดเหลืองและปูจากทะเลจีนตะวันออกเป็นวัตถุดิบหลักของอาหารท้องถิ่น'),
  'shijiazhuang/bridge': ('สะพานจ้าวโจว', 'สะพานโค้งหินอายุ 1,400 ปีแห่งนี้เป็นสะพานโค้งแบบเปิดช่องว่างที่เก่าแก่ที่สุดในโลก'),
  'shijiazhuang/clifftemple': ('ภูเขาชางเหยียน', 'สะพานวัดที่แขวนอยู่ระหว่างหน้าผาแห่งนี้เป็นฉากหลังของภาพยนตร์นับไม่ถ้วน'),
  'shijiazhuang/redbase': ('หมู่บ้านซีไป่โป', 'หมู่บ้านแห่งนี้เป็นสถานที่ศักดิ์สิทธิ์ของการท่องเที่ยวเชิงประวัติศาสตร์การปฏิวัติจีน ซึ่งเป็นที่วางแผนการก่อตั้งสาธารณรัฐประชาชนจีน.'),
  'shijiazhuang/pharma': ('เมืองแห่งอุตสาหกรรมยา', 'เมืองนี้เป็นศูนย์กลางการผลิตยาปฏิชีวนะและเป็นหนึ่งในผู้ผลิตยาที่ใหญ่ที่สุดของจีน.'),
  'taiyuan/jincitemple': ('วัดจิ้นฉือ', 'วัดจิ้นฉือเป็นสวนวัดที่งดงามที่สุดในภาคเหนือของจีน มีรูปปั้นและน้ำพุที่มีอายุเก่าแก่กว่าสามพันปี.'),
  'taiyuan/coalcart': ('ดินแดนถ่านหิน', 'แหล่งถ่านหินของมณฑลชานซีเป็นแหล่งพลังงานสำคัญของจีน และเมืองไท่หยวนคือเมืองหลวงแห่งความมั่งคั่งนี้.'),
  'taiyuan/vinegar': ('น้ำส้มสายชูหมักชานซี', 'น้ำส้มสายชูหมักที่บ่มจนได้ที่นี้เป็นรสเปรี้ยวที่ขาดไม่ได้ในอาหารของมณฑลชานซี.'),
  'taiyuan/twinpagoda': ('เจดีย์คู่', 'เจดีย์แปดเหลี่ยมสมัยราชวงศ์หมิงสององค์นี้ตั้งตระหง่านเคียงข้างกัน และเป็นสัญลักษณ์ของเมือง.'),
  'hohhot/lamatemple': ('วัดต้าจ้าวซื่อ', 'วัดพุทธนิกายทิเบตแห่งนี้มีชื่อเสียงจากพระพุทธรูปเงิน และเป็นศูนย์กลางทางจิตวิญญาณของเมือง.'),
  'hohhot/dairy': ('เมืองหลวงนม', 'แบรนด์ผลิตภัณฑ์นมที่ใหญ่ที่สุดของจีนถือกำเนิดขึ้นที่นี่ ทำให้เมืองนี้ได้ชื่อว่าเป็น "เมืองหลวงแห่งนม".'),
  'hohhot/wrestling': ('มวยปล้ำมองโกเลีย', 'มวยปล้ำโบเค่อ ซึ่งเป็นไฮไลต์ของเทศกาลนาดัม แสดงให้เห็นถึงพละกำลังของชาวทุ่งหญ้า.'),
  'hohhot/prairie': ('ทุ่งหญ้ามองโกเลีย', 'นอกเมืองออกไปคือทุ่งหญ้ามองโกเลียสีเขียวขจีที่เต็มไปด้วยม้าและฝูงสัตว์.'),
  'sanya/resortbeach': ('อ่าวหย่าหลง', 'หาดทรายขาวละเอียดและน้ำทะเลสีครามของอ่าวหย่าหลงเปรียบเสมือนฮาวายของจีน.'),
  'sanya/guanyin': ('พระโพธิสัตว์กวนอิม', 'พระโพธิสัตว์กวนอิมองค์นี้มีความสูง 108 เมตรเหนือทะเล และเป็นหนึ่งในรูปปั้นเทพธิดาที่สูงที่สุดในโลก.'),
  'sanya/diving': ('การดำน้ำ', 'ด้วยน้ำทะเลที่อบอุ่นใสสะอาดและแนวปะการัง ซานย่าจึงเป็นสวรรค์ของการดำน้ำของจีน.'),
  'sanya/coconutdrink': ('น้ำมะพร้าว', 'น้ำมะพร้าวสดจากสวนเขตร้อนเป็นเครื่องดื่มดับกระหายคลายร้อนของเกาะแห่งนี้.'),
  'yangzhou/slenderlake': ('ทะเลสาบโช่วซีหู', 'ทะเลสาบที่เรียวยาวแห่งนี้มีต้นหลิวและสะพานสีขาว งดงามราวกับภาพวาด.'),
  'yangzhou/friedrice': ('ข้าวผัดหยางโจว', 'ข้าวผัดสีทองที่คลุกเคล้ากับกุ้งและไข่เป็นอาหารคลาสสิกที่มีชื่อเสียงระดับโลก'),
  'yangzhou/morningtea': ('ชายามเช้า', 'การรับประทานอาหารเช้าอันหรูหราด้วยซาลาเปานึ่งและชาเป็นประเพณีของหยางโจว'),
  'yangzhou/gegarden': ('สวนเกอ', 'สวนไผ่ที่จำลองสี่ฤดูด้วยหินเป็นผลงานชิ้นเอกของการออกแบบสวนคลาสสิก'),
  'weihai/navalisland': ('เกาะหลิวกง', 'เกาะแห่งนี้เป็นฐานทัพของกองเรือเป่ยหยางและเป็นพยานประวัติศาสตร์กองทัพเรือจีนสมัยใหม่'),
  'weihai/swan': ('ทะเลสาบหงส์', 'ทุกฤดูหนาว หงส์วูเปอร์หลายร้อยตัวจากไซบีเรียจะมาเยือนทะเลสาบชายฝั่งแห่งนี้'),
  'weihai/seacucumber': ('ปลิงทะเล', 'ปลิงทะเลที่เติบโตในน้ำเย็นสะอาดเป็นอาหารทะเลล้ำค่าที่สุดของเมืองนี้'),
  'weihai/cape': ('แหลมสุดตะวันออกของจีน', 'แหลมที่อยู่ทางตะวันออกสุดของจีนแห่งนี้เป็นที่แรกที่ดวงอาทิตย์ทักทายประเทศ'),
  'handan/taichi': ('ไทเก๊ก', 'เมืองกว่างฝูซึ่งเป็นแหล่งกำเนิดของไทเก๊กตระกูลหยางและอู๋เป็นบ้านเกิดของไท่จี๋ฉวน'),
  'handan/congtai': ('หอคอยฉงไถ', 'หอคอยดินจากอาณาจักรจ้าวโบราณแห่งนี้เป็นพยานประวัติศาสตร์กว่า 2,000 ปี'),
  'handan/idiom': ('เมืองแห่งสำนวน', 'สำนวนจีนกว่า 1,500 สำนวนถือกำเนิดขึ้นที่นี่ ทำให้หานตานเป็น "เมืองแห่งสำนวน"'),
  'handan/ciporcelain': ('เครื่องเคลือบฉือโจว', 'เครื่องเคลือบฉือโจวสีดำบนพื้นขาวเป็นงานเซรามิกพื้นบ้านคลาสสิก'),
  'daqing/oilpump': ('แหล่งน้ำมัน', 'แหล่งน้ำมันที่ใหญ่ที่สุดของจีนแห่งนี้เต็มไปด้วยปั๊มน้ำมันที่ผงกหัวขึ้นลง'),
  'daqing/oilworker': ('คนเหล็ก', 'ความมุ่งมั่นของหวัง จิ้นซี วีรบุรุษคนงานน้ำมันเป็นจิตวิญญาณผู้ก่อตั้งเมืองนี้'),
  'daqing/reedlake': ('พื้นที่ชุ่มน้ำ', 'ทะเลสาบกกกว้างใหญ่ท่ามกลางบ่อน้ำมันเป็นที่อยู่อาศัยของนกกระเรียนและหงส์'),
  'daqing/hotspring': ('น้ำพุร้อน', 'น้ำแร่ร้อนจากใต้ดินมอบการพักผ่อนบำบัดในภาคเหนือที่หนาวเย็น'),
  'zibo/bbq': ('บาร์บีคิวจือปั๋ว', 'บาร์บีคิวเสียบไม้ที่ย่างบนเตาถ่านขนาดเล็กและห่อด้วยแป้งแพนเค้กบาง ๆ เป็นกระแสความนิยมที่แพร่หลายไปทั่วประเทศ.'),
  'zibo/cuju': ('คูจู', 'คูจู กีฬาฟุตบอลที่เก่าแก่ที่สุดในโลก เคยมีการเล่นกันในเมืองหลินจือ ซึ่งเป็นเมืองหลวงโบราณของแคว้นฉี.'),
  'zibo/ceramic': ('เครื่องปั้นดินเผาจือปั๋ว', 'ด้วยเตาเผาที่มีอายุยาวนานนับพันปี เมืองนี้จึงเป็นศูนย์กลางเครื่องปั้นดินเผาของภาคเหนือของจีน.'),
  'zibo/glass': ('เครื่องแก้วหลิวหลี', 'หลิวหลีเป็นงานฝีมือที่ทำด้วยมือจากแก้วหลอมสี ซึ่งเปล่งประกายเรืองรอง.'),
  'taian/mounttai': ('ภูเขาไท่', 'ภูเขาไท่เป็นประมุขแห่งห้ายอดเขาศักดิ์สิทธิ์ และเป็นยอดเขาที่ศักดิ์สิทธิ์ที่สุดที่จักรพรรดิเคยใช้ประกอบพิธีบวงสรวงสวรรค์.'),
  'taian/sunrise': ('ชมพระอาทิตย์ขึ้นบนยอดเขา', 'การได้ชมพระอาทิตย์ขึ้นเหนือทะเลหมอกเป็นรางวัลของการปีนภูเขาไท่.'),
  'taian/stonesteps': ('บันไดหิน', 'บันไดหิน 7,000 ขั้นสู่ยอดเขาเป็นบททดสอบทางกายภาพของเส้นทางแสวงบุญ.'),
  'taian/daitemple': ('วัดไต้', 'วัดอันยิ่งใหญ่ที่เชิงเขาแห่งนี้เป็นที่ที่จักรพรรดิเตรียมตัวสำหรับพิธีบวงสรวงภูเขาไท่.'),
  'lianyungang/monkey': ('ภูเขาฮัวกั่วซาน', 'ภูเขาฮัวกั่วซาน ซึ่งเป็นบ้านเกิดของซุนหงอคงจากเรื่อง "ไซอิ๋ว" ตั้งตระหง่านอยู่ที่นี่.'),
  'lianyungang/seaport': ('ท่าเรือเหลียนหยุนกัง', 'ประตูทะเลตะวันออกของเส้นทางสายไหมแห่งนี้เป็นจุดสิ้นสุดฝั่งแปซิฟิกของสะพานรถไฟยูเรเชีย.'),
  'lianyungang/mountain': ('ภูเขาหยุนไถ', 'ด้วยยอดเขาที่สูงชันและป่าไม้ ภูเขาหยุนไถจึงเป็นภูเขาที่สูงที่สุดในมณฑลเจียงซู.'),
  'lianyungang/crystal': ('ดินแดนคริสตัล', 'ตงไห่ที่อยู่ใกล้เคียงเป็นที่ตั้งของตลาดคริสตัลควอตซ์ที่ใหญ่ที่สุดแห่งหนึ่งของโลก.'),
  'maanshan/libai': ('กวีหลี่ไป๋', 'เมืองริมแม่น้ำแห่งนี้เป็นที่พำนักสุดท้ายและสุสานของหลี่ไป๋ กวีผู้ยิ่งใหญ่ที่สุดของจีน.'),
  'maanshan/steel': ('เมืองเหล็กกล้า', 'โรงงานเหล็กกล้าหม่ากังทำให้เมืองนี้เป็นหนึ่งในฐานอุตสาหกรรมเหล็กและเหล็กกล้าของจีน.'),
  'maanshan/rivercliff': ('หน้าผาไฉ่สือจี๋', 'หน้าผาที่ทอดตัวลงสู่แม่น้ำแยงซีแห่งนี้เป็นฉากกวีในตำนานของหลี่ไป๋.'),
  'maanshan/moonwine': ('จันทราและสุรา', 'จันทราและสุราในบทกวีของหลี่ไป๋ยังคงได้รับการเฉลิมฉลองในเทศกาลริมแม่น้ำ'),
  'longyan/tulou': ('ถู่โหลวหย่งติ้ง', 'บ้านดินทรงกลมขนาดใหญ่ของชาวฮากกาที่กระจัดกระจายอยู่ตามเนินเขาเหล่านี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกจากยูเนสโก'),
  'longyan/redmeeting': ('การประชุมกู่เถียน', 'การประชุมครั้งประวัติศาสตร์ที่กำหนดทิศทางของกองทัพแดงจัดขึ้นที่หมู่บ้านแห่งนี้'),
  'longyan/hakka': ('วัฒนธรรมฮากกา', 'ชาวฮากกาซึ่งอพยพมาจากทางเหนือยังคงรักษาภาษาและอาหารของตนไว้ในแถบภูเขาเหล่านี้'),
  'longyan/mountain': ('ภูเขากวนจื้อ', 'ด้วยหน้าผาสีแดงและสระน้ำใสสะอาด ภูเขาแห่งนี้จึงเป็นไข่มุกธรรมชาติแห่งฝูเจี้ยนตอนใต้'),
  'beijing/great-wall': ('กำแพงเมืองจีน', 'กำแพงเมืองจีนเป็นป้อมปราการที่ยาวที่สุดในโลกกว่า 20,000 กิโลเมตร สร้างขึ้นตลอดหลายศตวรรษเพื่อปกป้องพรมแดนทางเหนือของจีน โดยส่วนปาต้าหลิงใกล้กรุงปักกิ่งซึ่งมีบันไดหินและหอสังเกตการณ์บนสันเขาเป็นส่วนที่ได้รับความนิยมมากที่สุด'),
  'beijing/temple': ('หอสักการะฟ้าเทียนถาน', 'เป็นหมู่สิ่งก่อสร้างศักดิ์สิทธิ์ที่จักรพรรดิราชวงศ์หมิงและชิงใช้ประกอบพิธีบวงสรวงสวรรค์เพื่อขอพืชผลอุดมสมบูรณ์ทุกปี โดยหลังคาทรงกลมสีน้ำเงินสามชั้นที่สร้างขึ้นโดยไม่ใช้ตะปูแม้แต่ตัวเดียวเป็นหนึ่งในสัญลักษณ์ที่โดดเด่นที่สุดของสถาปัตยกรรมจีน'),
  'beijing/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์อิฐสูงประมาณ 57 เมตร 13 ชั้นจากราชวงศ์เหลียวแห่งนี้ มีลวดลายแกะสลักและรูปทรงแปดเหลี่ยม ถือเป็นหนึ่งในสิ่งก่อสร้างที่เก่าแก่ที่สุดที่ยังคงหลงเหลืออยู่ในกรุงปักกิ่ง เป็นประจักษ์พยานประวัติศาสตร์ยาวนานนับพันปีของเมือง'),
  'beijing/opera': ('งิ้วปักกิ่ง', 'งิ้วปักกิ่งเป็นการแสดงละครจีนโบราณที่มีอายุ 200 ปี ผสมผสานการร้อง การพูด ศิลปะการต่อสู้ และกายกรรม โดยใบหน้าที่แต่งแต้มสีสัน (เหลียนผู่) ของนักแสดงจะเผยให้เห็นถึงลักษณะของตัวละคร เช่น สีแดงหมายถึงความซื่อสัตย์ และสีขาวหมายถึงความเจ้าเล่ห์'),
};
